// SPDX-License-Identifier: MITpackage logimport (	"context"	"testing"	"go.uber.org/zap"	"go.uber.org/zap/zapcore"	"go.uber.org/zap/zaptest/observer")func TestNewID(t *testing.T) {	id := NewID()	if len(id) != 8 {		t.Errorf("expected 8 chars, got %d: %q", len(id), id)	}}func TestNewID_Unique(t *testing.T) {	a := NewID()	b := NewID()	if a == b {		t.Error("expected unique IDs")	}}func TestWithCorrelationID(t *testing.T) {	ctx := context.Background()	ctx2 := WithCorrelationID(ctx, "abc123")	id, ok := ctx2.Value(correlationIDKey).(string)	if !ok {		t.Fatal("correlation ID not stored in context")	}	if id != "abc123" {		t.Errorf("expected abc123, got %s", id)	}	if _, ok := ctx.Value(correlationIDKey).(string); ok {		t.Error("original context must not be modified")	}}func TestWithCorrelationID_EmptyGenerates(t *testing.T) {	ctx := WithCorrelationID(context.Background(), "")	if id, ok := ctx.Value(correlationIDKey).(string); !ok || id == "" {		t.Errorf("expected generated ID, got %q", id)	}}func TestWithContext_NoCorrelationID(t *testing.T) {	observed, logs := observer.New(zap.InfoLevel)	old := defaultLogger	defaultLogger = zap.New(observed)	defer func() { defaultLogger = old }()	logger := WithContext(context.Background())	logger.Info("test")	if logs.Len() != 1 {		t.Fatalf("expected 1 log, got %d", logs.Len())	}	entry := logs.All()[0]	if entry.Level != zapcore.InfoLevel {		t.Errorf("expected info level, got %v", entry.Level)	}}func TestWithContext_WithCorrelationID(t *testing.T) {	observed, logs := observer.New(zap.InfoLevel)	old := defaultLogger	defaultLogger = zap.New(observed)	defer func() { defaultLogger = old }()	ctx := WithCorrelationID(context.Background(), "xyz789")	logger := WithContext(ctx)	logger.Info("test")	if logs.Len() != 1 {		t.Fatalf("expected 1 log, got %d", logs.Len())	}	entry := logs.All()[0]	corrID := entry.ContextMap()["correlation_id"]	if corrID != "xyz789" {		t.Errorf("expected correlation_id=xyz789, got %v", corrID)	}}func TestWithContext_OriginalUnchanged(t *testing.T) {	old := defaultLogger	defer func() { defaultLogger = old }()	ctx := WithCorrelationID(context.Background(), "id1")	logger1 := WithContext(ctx)	ctx2 := WithCorrelationID(context.Background(), "id2")	logger2 := WithContext(ctx2)	if logger1 == logger2 {		t.Error("loggers with different correlation IDs should be different instances")	}}
